def predict_next_frame(frame, action, xy=None):
    """
    Predict the next frame for the grid game.

    Rules inferred from the data:

    • ACTION5:
        – In row 53 change the right‑most cell with value 2 to 3.
        – Draw a hollow rectangle of colour 4 whose top‑left corner is at
          (row 56, col 41) and bottom‑right corner at (row 61, col 46).

    • ACTION6(x, y):
        – Treat (x, y) as the centre of a 6×6 hollow rectangle.
        – The rectangle’s top‑left corner is therefore at (row y‑3, col x‑1)
          and its bottom‑right corner at (row y+2, col x+2).
        – Fill the perimeter of this rectangle with colour 4
          (top and bottom edges fully, left and right edges only on the
           intermediate rows).

    All other actions leave the board unchanged.
    """
    # Deep copy of the frame
    new_frame = [row[:] for row in frame]

    if action == "ACTION5":
        # ---- change right‑most 2 → 3 in row 53 -----------------
        r = 53
        if 0 <= r < len(new_frame):
            row_vals = new_frame[r]
            for c in range(len(row_vals) - 1, -1, -1):
                if row_vals[c] == 2:
                    new_frame[r][c] = 3
                    break

        # ---- draw fixed hollow rectangle (41‑46, 56‑61) ----------
        top, bottom = 56, 61
        left, right = 41, 46
        for rr in range(top, bottom + 1):
            if not (0 <= rr < len(new_frame)):
                continue
            row = new_frame[rr]
            if rr == top or rr == bottom:
                for cc in range(left, right + 1):
                    if 0 <= cc < len(row):
                        row[cc] = 4
            else:
                for cc in (left, right):
                    if 0 <= cc < len(row):
                        row[cc] = 4

    elif action == "ACTION6" and xy is not None:
        # ---- draw hollow rectangle centred at (x, y) ----------
        x, y = xy          # x = column, y = row
        top = y - 3
        bottom = y + 2
        left = x - 1
        right = x + 2

        for rr in range(top, bottom + 1):
            if not (0 <= rr < len(new_frame)):
                continue
            row = new_frame[rr]
            if rr == top or rr == bottom:
                for cc in range(left, right + 1):
                    if 0 <= cc < len(row):
                        row[cc] = 4
            else:
                for cc in (left, right):
                    if 0 <= cc < len(row):
                        row[cc] = 4

    # Other actions produce no change.
    return new_frame

